79	const LOCAL_COMMAND_TAG_PATTERN = /<(command-name|command-message|command-args|local-command-stdout|local-command-stderr)>[\s\S]*?<\/\1>/g;
80	function stripMarkerTags(text) {
81	    return text.replace(LOCAL_COMMAND_TAG_PATTERN, "");
