85	 * `null` if nothing meaningful remains (caller should skip the message).
86	 * Preserves real prose that's mixed in alongside the markers — e.g. a
87	 * message like `<command-name>…</command-name>hi` becomes `hi`.
88	 */
89	export function stripLocalCommandMetadata(content) {
90	    if (typeof content === "string") {
91	        const stripped = stripMarkerTags(content);
